"""
This module contains the main game logic for Checkers (Draughts).
"""

class Board:
    def __init__(self):
        # Initialize the board with alternating pieces
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'r'
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'b'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

class Piece:
    def __init__(self, color):
        self.color = color

    def can_capture(self, direction):
        return direction in ('up-left', 'up-right', 'down-left', 'down-right')

class Player:
    def __init__(self, color):
        self.color = color

class Move:
    def __init__(self, start, end):
        self.start = start
        self.end = end

    def is_capture(self):
        return abs(self.start[0] - self.end[0]) == 2 and abs(self.start[1] - self.end[1]) == 2

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'
        self.game_over = False

    def switch_player(self):
        if self.current_player == 'red':
            self.current_player = 'black'
        else:
            self.current_player = 'red'

    def make_move(self, move: Move):
        start_x, start_y = move.start
        end_x, end_y = move.end

        piece = self.board.board[start_x][start_y]
        if piece and piece.color == self.current_player:
            self.board.board[end_x][end_y] = piece
            self.board.board[start_x][start_y] = ' '
